void main() {
  String name = 'Dart';
  int year = 2011;
  double version = 3.0;
  bool isStable = true;
  List<String> features = ['Sound null safety', 'Pattern matching'];

  print('$name $version ($year)');
  print('Stable: $isStable');
  print('Features: $features');
}
